 84	  if (!intent.startsWith(IMAGE_UPLOAD_INTENT_PREFIX)) return null;
 85	  const path = intent.slice(IMAGE_UPLOAD_INTENT_PREFIX.length);
 86	  return path.length > 0 ? path : null;
