 95	 */
 96	export const uploadedImageKey = (
 97	  targetPath: string,
 98	  contentType: string,
 99	  seed: number,
100	): string => {
101	  const slug = targetPath.replace(/[^a-zA-Z0-9]+/g, '-').replace(/^-+|-+$/g, '');
102	  return `images/uploads/${slug}-${seed}.${extensionForType(contentType)}`;
