105	/**
106	 * The form-name prefix for a single translation value. Translation keys contain
107	 * dots (`main.newsletter.title`), which collide with the dotted-path convention,
108	 * so translation inputs are named `TRANSLATION_FIELD_PREFIX<locale>:<key>` and
109	 * collected by `collectTranslations` rather than parsed by `assembleOverrides`
110	 * (which skips them). The key is kept whole — never split on its dots.
111	 */
112	export const TRANSLATION_FIELD_PREFIX = 't:';
113	
114	export const translationFieldName = (locale: 'en' | 'fr', key: string): string =>
115	  `${TRANSLATION_FIELD_PREFIX}${locale}:${key}`;
116	
117	const isTranslationField = (name: string): boolean =>
118	  name.startsWith(TRANSLATION_FIELD_PREFIX);
119	
120	/**
121	 * Collect every `t:<locale>:<key>` form field into the bilingual translations
122	 * override, e.g. `t:en:main.newsletter.title` → `{ en: { 'main.newsletter.title':
123	 * '…' } }`. The key keeps its dots verbatim (it is a single map key, not a path).
124	 */
125	export const collectTranslations = (
126	  entries: Iterable<readonly [string, FormDataEntryValue]>,
127	): { readonly en: Record<string, string>; readonly fr: Record<string, string> } => {
128	  const en: Record<string, string> = {};
129	  const fr: Record<string, string> = {};
130	  for (const [name, value] of entries) {
131	    if (typeof value !== 'string' || !isTranslationField(name)) continue;
132	    const rest = name.slice(TRANSLATION_FIELD_PREFIX.length);
133	    const sep = rest.indexOf(':');
134	    if (sep === -1) continue;
135	    const locale = rest.slice(0, sep);
136	    const key = rest.slice(sep + 1);
137	    if (key === '') continue;
138	    if (locale === 'en') en[key] = value;
139	    else if (locale === 'fr') fr[key] = value;
140	  }
141	  return { en, fr };
142	};
