144	const isIndex = (segment: string): boolean => /^\d+$/.test(segment);
145	
146	/**
147	 * Set `value` at the dotted `path` inside `root`, creating intermediate objects
148	 * (or arrays, when the next segment is numeric) as needed. Mirrors the
149	 * paulo-suzanne admin's `setPath` but typed to `Json`.
150	 */
151	const setPath = (root: MutableJsonObject, path: string[], value: Json): void => {
152	  if (path.length === 0) return;
153	  let cursor: MutableJsonObject | Json[] = root;
154	  for (let i = 0; i < path.length - 1; i += 1) {
155	    const segment = path[i];
156	    const next = path[i + 1];
157	    if (segment === undefined || next === undefined) return;
158	    const key = Array.isArray(cursor) ? Number(segment) : segment;
159	    const existing = (cursor as MutableJsonObject)[key as keyof typeof cursor];
160	    if (isPlainObject(existing as Json) || Array.isArray(existing)) {
161	      cursor = existing as MutableJsonObject | Json[];
162	    } else {
163	      const container: MutableJsonObject | Json[] = isIndex(next) ? [] : {};
164	      (cursor as MutableJsonObject)[String(key)] = container;
165	      cursor = container;
166	    }
167	  }
168	  const leaf = path[path.length - 1];
169	  if (leaf === undefined) return;
170	  if (Array.isArray(cursor) && isIndex(leaf)) {
171	    cursor[Number(leaf)] = value;
172	  } else {
173	    (cursor as MutableJsonObject)[leaf] = value;
174	  }
175	};
