177	/**
178	 * Assemble the nested override object from the editor form. Only entries whose
179	 * name is a dotted path are taken; control fields (`intent`, anything starting
180	 * with `_`) and non-string values (files) are skipped. A leaf named `chapter` /
181	 * `verse` is coerced to a number so the `BibleRef` integer fields decode.
182	 */
183	export const assembleOverrides = (
184	  entries: Iterable<readonly [string, FormDataEntryValue]>,
185	): Json => {
186	  const root: MutableJsonObject = {};
187	  for (const [name, value] of entries) {
188	    if (typeof value !== 'string') continue;
189	    if (name === 'intent' || name.startsWith('_')) continue;
190	    if (isTranslationField(name)) continue;
191	    const path = name.split('.');
192	    const leaf = path[path.length - 1];
193	    const coerced: Json =
194	      (leaf === 'chapter' || leaf === 'verse') && value.trim() !== ''
195	        ? Number(value)
196	        : value;
197	    setPath(root, path, coerced);
198	  }
199	  return root;
200	};
201	
202	/**
203	 * Deep-merge `overrides` onto `base`, returning a new value. Objects merge
204	 * key-by-key; arrays merge element-by-element by index (so editing
205	 * `conferences.0.themeName.en` overlays only that leaf and leaves
206	 * `conferences.0.speakers` untouched); every other value (string / number /
207	 * boolean / null) is replaced. `base` and `overrides` are never mutated.
208	 */
209	export const deepMerge = (base: Json, overrides: Json): Json => {
210	  if (isPlainObject(base) && isPlainObject(overrides)) {
211	    const result: MutableJsonObject = { ...base };
212	    for (const key of Object.keys(overrides)) {
213	      const next = overrides[key];
214	      result[key] =
215	        key in base && next !== undefined
216	          ? deepMerge(base[key] as Json, next)
217	          : (next as Json);
218	    }
219	    return result;
220	  }
221	  if (Array.isArray(base) && Array.isArray(overrides)) {
222	    const result: Json[] = [...base];
223	    for (let i = 0; i < overrides.length; i += 1) {
224	      const next = overrides[i];
225	      if (next === undefined) continue;
226	      result[i] = i < base.length ? deepMerge(base[i] as Json, next) : next;
227	    }
228	    return result;
229	  }
230	  return overrides;
231	};
