233	/** Set the leaf at a dotted `path` on a structurally-cloned copy of `doc`. */
234	export const setAtPath = (doc: Json, path: string, value: Json): Json => {
235	  const clone = structuredClone(doc) as MutableJsonObject;
236	  setPath(clone, path.split('.'), value);
237	  return clone;
238	};

