262	    /**
263	     * Re-encode a decoded document to its canonical JSON and store it at
264	     * `draftKey`, rejecting with a 502 `IssueError` on a storage failure.
265	     * Returns the encoded object so callers can hand it back to the view.
266	     */
267	    const storeDraft = (
268	      draftKey: string,
269	      decoded: SiteContentType,
270	    ): Effect.Effect<EncodedDoc, IssueError> =>
271	      Effect.gen(function* () {
272	        // A decoded `SiteContent` always re-encodes — a failure here is a bug,
273	        // not a user error, so it dies rather than masquerading as an
274	        // `IssueError`.
275	        const json = yield* encodeDocumentJson(decoded).pipe(Effect.orDie);
276	        yield* storage.put(draftKey, json, 'application/json').pipe(
277	          Effect.mapError(
278	            (cause) =>
279	              new IssueError({
280	                message: `Saving the draft failed — is the bucket configured? ${String(cause)}`,
281	                issues: [],
282	                status: 502,
283	              }),
284	          ),
285	        );
286	        return (yield* encodeDocument(decoded).pipe(Effect.orDie)) as EncodedDoc;
287	      });
