289	    const editDocument = Effect.fn('DraftEditor.editDocument')(function* (
290	      scope: ContentScope,
291	      override: Json,
292	    ) {
293	      const { draftKey } = scopeKeys(scope);
294	      const { content: current } = yield* load(scope);
295	      const base = (yield* encodeDocument(current).pipe(Effect.orDie)) as Json;
296	      const merged = deepMerge(base, override);
297	      const decoded = yield* decodeOrReject(merged);
298	      return yield* storeDraft(draftKey, decoded);
299	    });
