314	    const publish = Effect.fn('DraftEditor.publish')(function* (
315	      scope: ContentScope,
316	    ) {
317	      const { draftKey, publishedKey } = scopeKeys(scope);
318	      const { content: current } = yield* load(scope);
319	      const json = yield* encodeDocumentJson(current).pipe(Effect.orDie);
320	      yield* storage.put(publishedKey, json, 'application/json').pipe(
321	        Effect.mapError(
322	          (cause) =>
323	            new IssueError({
324	              message: `Publishing failed — is the bucket configured? ${String(cause)}`,
325	              issues: [],
326	              status: 502,
327	            }),
328	        ),
329	      );
330	      // Best-effort cleanup; correctness does NOT depend on it (`load`
331	      // reconciles draft-vs-published by `lastModified` and only reopens a
332	      // strictly-newer draft, so a leftover draft can never reopen stale
333	      // content). Hence it must not fail the publish — the live document is
334	      // already written.
335	      yield* storage.delete(draftKey).pipe(Effect.ignore);
